function numberToWords(n2) {
  const ones = [
    "",
    "One",
    "Two",
    "Three",
    "Four",
    "Five",
    "Six",
    "Seven",
    "Eight",
    "Nine",
    "Ten",
    "Eleven",
    "Twelve",
    "Thirteen",
    "Fourteen",
    "Fifteen",
    "Sixteen",
    "Seventeen",
    "Eighteen",
    "Nineteen"
  ];
  const tens = [
    "",
    "",
    "Twenty",
    "Thirty",
    "Forty",
    "Fifty",
    "Sixty",
    "Seventy",
    "Eighty",
    "Ninety"
  ];
  if (n2 === 0) return "Zero";
  if (n2 < 20) return ones[n2];
  if (n2 < 100)
    return `${tens[Math.floor(n2 / 10)]}${n2 % 10 ? ` ${ones[n2 % 10]}` : ""}`;
  if (n2 < 1e3)
    return `${ones[Math.floor(n2 / 100)]} Hundred${n2 % 100 ? ` ${numberToWords(n2 % 100)}` : ""}`;
  if (n2 < 1e5)
    return `${numberToWords(Math.floor(n2 / 1e3))} Thousand${n2 % 1e3 ? ` ${numberToWords(n2 % 1e3)}` : ""}`;
  return `${numberToWords(Math.floor(n2 / 1e5))} Lakh${n2 % 1e5 ? ` ${numberToWords(n2 % 1e5)}` : ""}`;
}
